<template>
  <div>
    <article
      class="comment"
      :class="{
        pinned: comment.pinned
      }"
      :style="{
        'box-shadow': boxShadowStyle
      }"
      v-if="!isEmpty"
    >
      <div class="content-wrapper full">
        <div class="flexrow">
          <validation-tag
            class="flexrow-item"
            :task="{ task_status_id: comment.task_status.id }"
            :is-static="true"
            :thin="!isChange"
          />
          <people-avatar
            class="flexrow-item"
            :size="25"
            :font-size="12"
            :person="comment.person"
            :is-link="!isCurrentUserClient"
            v-if="comment.person?.id"
          />
          <people-name
            class="flexrow-item strong"
            :person="comment.person"
            v-if="comment.person?.id"
          />
          <div class="filler"></div>
          <span class="flexrow-item date" :title="fullDate">
            {{ shortDate }}
          </span>
          <div
            class="flexrow-item menu-wrapper"
            v-if="
              isPinnable || isEditable || canToggleForClient || canMoveComment
            "
          >
            <chevron-down-icon class="menu-icon" @click="toggleCommentMenu" />
            <comment-menu
              :is-pinnable="isPinnable"
              :is-pinned="comment.pinned"
              :is-editable="isEditable"
              :can-toggle-for-client="canToggleForClient"
              :can-move="canMoveComment"
              :is-for-client="Boolean(comment.for_client)"
              @pin-clicked="
                () => {
                  emit('pin-comment', comment)
                  toggleCommentMenu()
                }
              "
              @edit-clicked="
                () => {
                  emit('edit-comment', comment)
                  toggleCommentMenu()
                }
              "
              @delete-clicked="
                () => {
                  emit('delete-comment', comment)
                  toggleCommentMenu()
                }
              "
              @move-clicked="
                () => {
                  emit('move-comment', comment)
                  toggleCommentMenu()
                }
              "
              @toggle-for-client-clicked="
                () => {
                  emit('toggle-for-client', comment)
                  toggleCommentMenu()
                }
              "
              v-if="menuVisible"
            />
          </div>
        </div>
        <div class="flexrow-item comment-content">
          <div class="content">
            <p
              class="client-comment"
              v-if="isAuthorClient && !isCurrentUserClient"
            >
              {{ $t('comments.comment_from_client') }}
              <copy-icon
                class="copy-icon"
                :size="12"
                @click="emit('duplicate-comment', comment)"
              />
            </p>
            <p
              class="for-client-tag"
              v-if="comment.for_client && !isCurrentUserClient"
            >
              {{ $t('comments.for_client_badge') }}
            </p>
            <p
              v-html="
                renderComment(
                  comment.text,
                  comment.mentions,
                  comment.department_mentions || [],
                  personMap,
                  departmentMap,
                  taskTypes,
                  uniqueClassName
                )
              "
              class="comment-text"
              v-if="comment.text"
            ></p>
            <checklist
              class="checklist"
              :checklist="checklistItems"
              :disabled="true"
              :is-editable="isCheckable"
              @remove-task="removeTask"
              @emit-change="onChecklistChanged"
              @time-code-clicked="onChecklistTimecodeClicked"
              v-if="checklistItems.length > 0"
            />
            <p v-if="comment.attachment_files.length > 0">
              <a
                :href="getDownloadAttachmentPath(attachment)"
                :key="attachment.id"
                :title="attachment.name"
                target="_blank"
                v-for="attachment in pictureAttachments"
              >
                <img
                  class="attachment"
                  :src="getDownloadAttachmentPath(attachment)"
                />
              </a>
              <attachment-audio-player
                v-for="attachment in audioAttachments"
                :key="attachment.id"
                :src="getDownloadAttachmentPath(attachment)"
                :name="attachment.name"
                :download-href="getDownloadAttachmentPath(attachment)"
              />
              <attachment-video-player
                v-for="attachment in videoAttachments"
                :key="attachment.id"
                :src="getDownloadAttachmentPath(attachment)"
                :name="attachment.name"
                :download-href="getDownloadAttachmentPath(attachment)"
              />
              <a
                :href="getDownloadAttachmentPath(attachment)"
                :key="attachment.id"
                :title="attachment.name"
                class="flexrow"
                target="_blank"
                v-for="attachment in fileAttachments"
              >
                <paperclip-icon class="flexrow-item attachment-icon icon-1x" />
                <span class="flexrow-item">
                  {{ attachment.name }}
                </span>
              </a>
            </p>
            <div class="replies">
              <div
                :key="replyComment.id"
                class="reply-comment"
                v-for="replyComment in comment.replies || []"
              >
                <div class="flexrow">
                  <template v-if="replyComment.person?.id">
                    <people-avatar
                      class="flexrow-item"
                      :size="18"
                      :font-size="10"
                      :person="replyComment.person"
                      :is-link="!isCurrentUserClient"
                    />
                    <people-name
                      class="flexrow-item strong"
                      :person="replyComment.person"
                    />
                  </template>
                  <span
                    class="flexrow-item reply-date"
                    :title="replyFullDate(replyComment.date)"
                  >
                    {{ replyShortDate(replyComment.date) }}
                  </span>
                  <span class="filler"> </span>
                  <span
                    class="flexrow-item reply-delete"
                    :title="$t('main.delete')"
                    @click="onDeleteReplyClicked(replyComment)"
                    v-if="
                      isCurrentUserAdmin || replyComment.person_id === user.id
                    "
                  >
                    x
                  </span>
                </div>
                <p
                  v-html="
                    renderComment(
                      replyComment.text,
                      replyComment.mentions || [],
                      replyComment.department_mentions || [],
                      personMap,
                      departmentMap,
                      taskTypes,
                      uniqueClassName
                    )
                  "
                  class="comment-text"
                ></p>

                <p>
                  <a
                    :href="getDownloadAttachmentPath(attachment)"
                    :key="attachment.id"
                    :title="attachment.name"
                    target="_blank"
                    v-for="attachment in replyAttachmentMap.get(replyComment.id)
                      ?.pictures"
                  >
                    <img
                      class="attachment"
                      :src="getDownloadAttachmentPath(attachment)"
                    />
                  </a>
                  <attachment-audio-player
                    v-for="attachment in replyAttachmentMap.get(replyComment.id)
                      ?.audio"
                    :key="attachment.id"
                    :src="getDownloadAttachmentPath(attachment)"
                    :name="attachment.name"
                    :download-href="getDownloadAttachmentPath(attachment)"
                  />
                  <attachment-video-player
                    v-for="attachment in replyAttachmentMap.get(replyComment.id)
                      ?.video"
                    :key="attachment.id"
                    :src="getDownloadAttachmentPath(attachment)"
                    :name="attachment.name"
                    :download-href="getDownloadAttachmentPath(attachment)"
                  />
                  <a
                    :href="getDownloadAttachmentPath(attachment)"
                    :key="attachment.id"
                    :title="attachment.name"
                    class="flexrow"
                    target="_blank"
                    v-for="attachment in replyAttachmentMap.get(replyComment.id)
                      ?.files"
                  >
                    <paperclip-icon
                      class="flexrow-item attachment-icon icon-1x"
                    />
                    <span class="flexrow-item">
                      {{ attachment.name }}
                    </span>
                  </a>
                </p>
              </div>
              <div
                @drop="onDrop"
                @dragover="onDragover"
                @dragleave="onDragleave"
              >
                <template v-if="showReply">
                  <at-ta
                    :ats="['#', '@']"
                    :members="[...membersForAts['@'], ...membersForAts['#']]"
                    :filter-match="atOptionsFilter"
                    name-key="full_name"
                    :limit="2"
                    @update:value="onAtTextChanged"
                  >
                    <template #item="{ item }">
                      <template v-if="item.isTime"> ⏱️ frame </template>
                      <template v-else-if="item.isDepartment">
                        <span
                          class="mr05"
                          :style="{
                            background: item.color,
                            width: '10px',
                            height: '10px',
                            'border-radius': '50%'
                          }"
                        >
                          &nbsp;
                        </span>
                        {{ item.full_name }}
                      </template>
                      <template v-else-if="item.isTaskType">
                        <task-type-name
                          :task-type="{
                            color: item.color,
                            name: item.full_name
                          }"
                          :is-link="false"
                          thin
                        />
                      </template>
                      <template v-else>
                        <div class="flexrow">
                          <people-avatar
                            class="flexrow-item"
                            :person="item"
                            :size="20"
                            :font-size="11"
                            :is-lazy="false"
                            :is-link="false"
                          />
                          <span class="flexrow-item">
                            {{ item.full_name }}
                          </span>
                        </div>
                      </template>
                    </template>
                    <textarea
                      ref="replyRef"
                      class="reply"
                      @keyup.ctrl.enter="onReplyClicked"
                      @dragover="onDragover"
                      @dragleave="onDragleave"
                      v-model="replyText"
                    />
                  </at-ta>
                  <div class="reply-attachments">
                    <div
                      :key="'attachment-' + index"
                      class="attachment-file"
                      v-for="(attach, index) in replyAttachments"
                    >
                      {{ shortenText(attach.get('file').name, 40) }}
                      <span @click="removeReplyAttachment(attach)">x</span>
                    </div>
                  </div>
                  <div class="flexrow ml05">
                    <emoji-button @select="onSelectEmoji" />
                    <button-simple
                      class="attachment-button"
                      icon="attach"
                      :title="$t('comments.add_attachment')"
                      @click="modals.addAttachment = true"
                    />
                    <span class="filler"></span>
                    <button-simple
                      class="reply-button"
                      :text="$t('main.reply')"
                      :is-loading="isReplyLoading"
                      @click="onReplyClicked"
                    />
                  </div>
                </template>
              </div>
            </div>

            <div
              class="flexrow"
              :title="isLikedBy"
              v-if="
                comment.text.length > 0 ||
                comment.previews.length > 0 ||
                comment.attachment_files.length > 0 ||
                comment.checklist?.length > 0
              "
            >
              <button
                class="like-button flexrow-item"
                :class="{
                  'like-button--empty': comment.like === undefined
                }"
                type="button"
                @click="acknowledgeComment(comment)"
              >
                <thumbs-up-icon class="icon-1x" />
                <span>{{ comment.acknowledgements.length }}</span>
              </button>
              <span class="filler"></span>
              <span
                class="flexrow-item reply-button"
                @click="showReplyWidget"
                v-if="!showReply && isReplyable"
              >
                {{ $t('main.reply') }}
              </span>
            </div>
            <div class="pinned-text" v-if="comment.pinned">
              {{ $t('comments.pinned') }}
            </div>
            <div
              class="edited-text"
              v-if="
                comment.editor_id && comment.editor_id !== comment.person_id
              "
            >
              {{
                $t('comments.edited_by', {
                  name: personMap.get(comment.editor_id)?.full_name
                })
              }}
            </div>
          </div>
        </div>
      </div>
      <div
        class="flexrow content-wrapper preview-info"
        v-if="comment.previews.length > 0 && !isConcept"
      >
        <router-link class="round-name revision" :to="previewRoute">
          {{
            comment.pinned
              ? $t('comments.pinned_revision')
              : $t('comments.revision')
          }}
          {{ comment.previews[0].revision }}
        </router-link>
        <a
          class="preview-link button"
          :href="comment.links[0]"
          :title="$t('playlists.actions.open_link')"
          target="_blank"
          v-if="!isCurrentUserArtist && comment.links?.[0]?.length"
        >
          <link-icon class="icon is-small" />
        </a>
        <span
          class="flexrow-item preview-status"
          :class="{ pointer: isCurrentUserManager }"
          :title="comment.previews[0].validation_status"
          :data-status="comment.previews[0].validation_status"
          @click="changePreviewValidationStatus(comment.previews)"
        ></span>
      </div>
    </article>
    <div class="empty-comment" v-else>
      <div class="flexrow content-wrapper">
        <validation-tag
          class="flexrow-item"
          :task="{ task_status_id: comment.task_status.id }"
          :is-static="true"
          :thin="!isChange"
        />
        <people-avatar
          class="flexrow-item"
          :person="comment.person"
          :size="25"
          :font-size="12"
          :is-link="!isCurrentUserClient"
        />
        <people-name class="flexrow-item strong" :person="comment.person" />
        <span class="filler"> </span>
        <span class="flexrow-item date" :title="fullDate">
          {{ shortDate }}
        </span>
        <div class="flexrow-item menu-wrapper" v-if="isPinnable || isEditable">
          <chevron-down-icon class="menu-icon" @click="toggleCommentMenu" />
          <comment-menu
            :is-pinnable="isPinnable"
            :is-editable="isEditable"
            :is-empty="true"
            @pin-clicked="
              () => {
                emit('pin-comment', comment)
                toggleCommentMenu()
              }
            "
            @edit-clicked="
              () => {
                emit('edit-comment', comment)
                toggleCommentMenu()
              }
            "
            @delete-clicked="
              () => {
                emit('delete-comment', comment)
                toggleCommentMenu()
              }
            "
            v-if="menuVisible"
          />
        </div>
      </div>
    </div>
    <add-attachment-modal
      ref="addAttachmentModalRef"
      :active="modals.addAttachment"
      :title="$t('comments.add_attachment_to_reply')"
      :name-prefix="attachmentNamePrefix"
      @cancel="modals.addAttachment = false"
      @confirm="addAttachmentToReply"
      v-if="modals.addAttachment"
    />
  </div>
</template>

<script setup>
import {
  computed,
  nextTick,
  onBeforeUnmount,
  onMounted,
  reactive,
  ref,
  watch
} from 'vue'
import { useRoute } from 'vue-router'
import { useStore } from 'vuex'
import AtTa from 'vue-at/dist/vue-at-textarea'
import moment from 'moment'
import {
  ChevronDownIcon,
  CopyIcon,
  LinkIcon,
  PaperclipIcon,
  ThumbsUpIcon
} from 'lucide-vue-next'

import files from '@/lib/files'
import { remove } from '@/lib/models'
import { getDownloadAttachmentPath, pluralizeEntityType } from '@/lib/path'
import { renderComment, replaceTimeWithTimecode } from '@/lib/render'
import { sortByName } from '@/lib/sorting'
import { parseDate } from '@/lib/time'
import stringHelpers from '@/lib/string'

import { useAtMentionsMembers } from '@/composables/atMentions'
import { domMixin } from '@/components/mixins/dom'

import AddAttachmentModal from '@/components/modals/AddAttachmentModal.vue'
import AttachmentAudioPlayer from '@/components/players/viewers/AttachmentAudioPlayer.vue'
import AttachmentVideoPlayer from '@/components/players/viewers/AttachmentVideoPlayer.vue'
import ButtonSimple from '@/components/widgets/ButtonSimple.vue'
import CommentMenu from '@/components/widgets/CommentMenu.vue'
import Checklist from '@/components/widgets/Checklist.vue'
import EmojiButton from '@/components/widgets/EmojiButton.vue'
import PeopleAvatar from '@/components/widgets/PeopleAvatar.vue'
import PeopleName from '@/components/widgets/PeopleName.vue'
import TaskTypeName from '@/components/widgets/TaskTypeName.vue'
import ValidationTag from '@/components/widgets/ValidationTag.vue'

const { pauseEvent } = domMixin.methods

const store = useStore()
const route = useRoute()

const emit = defineEmits([
  'ack-comment',
  'checklist-updated',
  'delete-comment',
  'duplicate-comment',
  'edit-comment',
  'move-comment',
  'pin-comment',
  'time-code-clicked',
  'toggle-for-client'
])

const props = defineProps({
  comment: {
    type: Object,
    default: () => {}
  },
  frame: {
    type: Number,
    default: 0
  },
  fps: {
    type: Number,
    default: 25
  },
  isChange: {
    type: Boolean,
    default: false
  },
  isCheckable: {
    type: Boolean,
    default: false
  },
  canMove: {
    type: Boolean,
    default: false
  },
  isEditable: {
    type: Boolean,
    default: false
  },
  isPinnable: {
    type: Boolean,
    default: false
  },
  isReplyable: {
    type: Boolean,
    default: false
  },
  taskTypes: {
    type: Array,
    default: () => []
  },
  team: {
    type: Array,
    default: () => []
  },
  task: {
    type: Object,
    default: null
  },
  revision: {
    type: Number,
    default: 1
  }
})

const replyRef = ref(null)
const addAttachmentModalRef = ref(null)

const { membersForAts, atOptionsFilter } = useAtMentionsMembers(
  () => props.team,
  () => props.taskTypes
)

const checklistItems = ref([])
const isReplyLoading = ref(false)
const menuVisible = ref(false)
const modals = reactive({
  addAttachment: false
})
const replyAttachments = ref([])
const replyText = ref('')
const showReply = ref(false)
const uniqueClassName = (Math.random() + 1).toString(36).substring(2)

let silent = false
let lastCall = 0

const departmentMap = computed(() => store.getters.departmentMap)
const isCurrentUserAdmin = computed(() => store.getters.isCurrentUserAdmin)
const isCurrentUserArtist = computed(() => store.getters.isCurrentUserArtist)
const isCurrentUserClient = computed(() => store.getters.isCurrentUserClient)
const isCurrentUserManager = computed(() => store.getters.isCurrentUserManager)
const personMap = computed(() => store.getters.personMap)
const taskTypeMap = computed(() => store.getters.taskTypeMap)
const user = computed(() => store.getters.user)

const attachmentNamePrefix = computed(() =>
  stringHelpers.attachmentNamePrefix(
    props.task?.entity_name,
    taskTypeMap.value.get(props.task?.task_type_id)?.name
  )
)

const isConcept = computed(() => {
  return route.path.includes('concept')
})

const canToggleForClient = computed(() => isCurrentUserManager.value)

const isPreviewBound = computed(() => {
  return Boolean(
    props.comment.preview_file_id ||
    (props.comment.previews && props.comment.previews.length > 0)
  )
})

const canMoveComment = computed(() => props.canMove && !isPreviewBound.value)

const isEmpty = computed(() => {
  return (
    props.comment.text.length === 0 &&
    (!props.comment.checklist || props.comment.checklist.length === 0) &&
    props.comment.attachment_files.length === 0 &&
    props.comment.previews.length === 0
  )
})

const previewRoute = computed(() => {
  let r = {
    name: 'task',
    params: {
      task_id: props.comment.object_id,
      production_id: props.task.project_id
    }
  }
  if (props.comment.previews.length > 0) {
    r = {
      name: 'task-preview',
      params: {
        task_id: props.comment.object_id,
        preview_id: props.comment.previews[0].id,
        production_id: props.task.project_id
      }
    }
  }
  if (props.task.episode_id) {
    r.name = `episode-${r.name}`
    r.params.episode_id = props.task.episode_id
  } else if (props.task.entity && props.task.entity.episode_id) {
    r.name = `episode-${r.name}`
    r.params.episode_id = props.task.entity.episode_id
  }
  const taskType = taskTypeMap.value.get(props.task.task_type_id)
  r.params.type = pluralizeEntityType(taskType.for_entity)
  return r
})

const isLikedBy = computed(() => {
  const personList = props.comment.acknowledgements
    .map(personId => personMap.value.get(personId))
    .filter(Boolean)
  return sortByName(personList)
    .map(p => p.name)
    .join(', ')
})

const commentAttachments = computed(() => {
  return props.comment.attachment_files.filter(
    attachment => !attachment.reply_id
  )
})

const pictureAttachments = computed(() => {
  return commentAttachments.value
    .filter(attachment => files.IMG_EXTENSIONS.includes(attachment.extension))
    .sort((a, b) =>
      a.name.localeCompare(b.name, undefined, {
        numeric: true
      })
    )
})

const audioAttachments = computed(() => {
  return commentAttachments.value.filter(attachment =>
    files.AUDIO_EXTENSIONS.includes(attachment.extension)
  )
})

const videoAttachments = computed(() => {
  return commentAttachments.value.filter(attachment =>
    files.VIDEO_EXTENSIONS.includes(attachment.extension)
  )
})

const fileAttachments = computed(() => {
  return commentAttachments.value.filter(
    attachment =>
      !files.IMG_EXTENSIONS.includes(attachment.extension) &&
      !files.AUDIO_EXTENSIONS.includes(attachment.extension) &&
      !files.VIDEO_EXTENSIONS.includes(attachment.extension)
  )
})

const replyAttachmentMap = computed(() => {
  const map = new Map()
  props.comment.attachment_files.forEach(attachment => {
    if (attachment.reply_id) {
      if (!map.has(attachment.reply_id)) {
        map.set(attachment.reply_id, {
          pictures: [],
          audio: [],
          video: [],
          files: []
        })
      }
      const bucket = map.get(attachment.reply_id)
      if (files.IMG_EXTENSIONS.includes(attachment.extension)) {
        bucket.pictures.push(attachment)
      } else if (files.AUDIO_EXTENSIONS.includes(attachment.extension)) {
        bucket.audio.push(attachment)
      } else if (files.VIDEO_EXTENSIONS.includes(attachment.extension)) {
        bucket.video.push(attachment)
      } else {
        bucket.files.push(attachment)
      }
    }
  })
  return map
})

const commentDate = computed(() => {
  return parseDate(props.comment.created_at)
})

const fullDate = computed(() => {
  return commentDate.value.tz(user.value.timezone).format('YYYY-MM-DD HH:mm:ss')
})

const shortDate = computed(() => {
  return renderDate(commentDate.value)
})

const boxShadowStyle = computed(() => {
  const status = props.comment.task_status
  return `0 0 3px 2px ${status.color}1F`
})

const isAuthorClient = computed(() => {
  const author =
    personMap.value.get(props.comment.person_id) || props.comment.person
  return author?.role === 'client'
})

const shortenText = (text, length) => {
  return stringHelpers.shortenText(text, length)
}

const replyFullDate = date => {
  return moment(parseDate(date))
    .tz(user.value.timezone)
    .format('YYYY-MM-DD HH:mm:ss')
}

const replyShortDate = date => {
  return renderDate(parseDate(date))
}

const renderDate = date => {
  date = moment(date)
  if (moment().isSame(date, 'd')) {
    return date.tz(user.value.timezone).format('HH:mm')
  } else {
    return date.tz(user.value.timezone).format('MM/DD')
  }
}

const toggleCommentMenu = () => {
  menuVisible.value = !menuVisible.value
}

const removeTask = entry => {
  checklistItems.value = remove(checklistItems.value, entry)
}

const onChecklistChanged = () => {
  const now = new Date().getTime()
  if (now - lastCall > 1000) {
    lastCall = now
    const comment = {
      id: props.comment.id,
      checklist: checklistItems.value.filter(item => item.text?.length)
    }
    emit('checklist-updated', comment)
  }
}

const acknowledgeComment = comment => {
  emit('ack-comment', comment)
}

const timeCodeClicked = event => {
  const data = { ...event.target.dataset }
  data.frame = data.frame - 1
  pauseEvent(event)
  emit('time-code-clicked', data)
}

const onChecklistTimecodeClicked = data => {
  emit('time-code-clicked', {
    versionRevision: data.revision,
    frame: data.frame - 1
  })
}

const changePreviewValidationStatus = previewFiles => {
  if (!isCurrentUserManager.value) {
    return
  }
  const statusMap = {
    validated: 'rejected',
    rejected: 'neutral',
    neutral: 'validated'
  }
  const status = statusMap[previewFiles[0].validation_status] || 'validated'
  previewFiles.forEach(previewFile => {
    store.dispatch('updatePreviewFileValidationStatus', { previewFile, status })
  })
}

const showReplyWidget = () => {
  showReply.value = true
  nextTick(() => {
    replyRef.value?.focus()
  })
}

const onDrop = event => {
  event.preventDefault()
  const droppedFiles = event.dataTransfer.files
  if (droppedFiles.length > 0) {
    const form = new FormData()
    form.append('file', droppedFiles[0])
    addAttachmentToReply([form])
  }
}

const onDragover = event => {
  event.preventDefault()
}

const onDragleave = event => {
  event.preventDefault()
}

const onReplyClicked = () => {
  isReplyLoading.value = true
  store
    .dispatch('replyToComment', {
      comment: props.comment,
      text: replyText.value,
      attachments: replyAttachments.value
    })
    .then(() => {
      isReplyLoading.value = false
      replyText.value = ''
      showReply.value = false
      replyAttachments.value = []
    })
    .catch(error => {
      console.error(error)
      isReplyLoading.value = false
    })
}

const onDeleteReplyClicked = reply => {
  store
    .dispatch('deleteReply', { comment: props.comment, reply })
    .then(() => {
      isReplyLoading.value = false
    })
    .catch(console.error)
}

const onAtTextChanged = input => {
  if (input.includes('@frame')) {
    replyText.value = replaceTimeWithTimecode(
      input,
      props.revision,
      props.frame + 1,
      props.fps
    )
  }
}

const onSelectEmoji = emoji => {
  const textarea = replyRef.value
  replyText.value = stringHelpers.insertInTextArea(textarea, emoji.i)
}

const addAttachmentToReply = addedFiles => {
  modals.addAttachment = false
  replyAttachments.value = replyAttachments.value.concat(addedFiles)
}

const removeReplyAttachment = attachment => {
  replyAttachments.value = replyAttachments.value.filter(a => a !== attachment)
}

const onPaste = event => {
  if (modals.addAttachment || !showReply.value) return
  if (replyRef.value !== document.activeElement) return
  const pastedFiles = event.clipboardData.files
  if (pastedFiles.length > 0) {
    const form = new FormData()
    form.append('file', pastedFiles[0])
    addAttachmentToReply([form])
  }
}

onMounted(() => {
  if (props.comment.checklist) {
    silent = true
    checklistItems.value = [...props.comment.checklist]
    nextTick().then(() => {
      silent = false
    })
  }
  Array.from(document.getElementsByClassName(uniqueClassName)).forEach(
    element => {
      element.addEventListener('click', timeCodeClicked)
    }
  )
  window.addEventListener('paste', onPaste, false)
})

onBeforeUnmount(() => {
  Array.from(document.getElementsByClassName(uniqueClassName)).forEach(
    element => {
      element.removeEventListener('click', timeCodeClicked)
    }
  )
  window.removeEventListener('paste', onPaste, false)
})

watch(
  () => props.comment.checklist,
  () => {
    silent = true
    checklistItems.value = [...props.comment.checklist]
    nextTick().then(() => {
      silent = false
    })
  }
)

watch(checklistItems, () => {
  if (!silent) {
    onChecklistChanged()
  }
})
</script>

